-4d94-a232-41b8ac5b09f0", "description": "Nizam Package membantu UMKM bergerak lebih cepat dengan penawaran yang jelas, positioning yang tegas, dan ajakan aksi yang tidak membingungkan calon buyer.", "offer_badge": "Campaign 2026", "offer_items": [{"title": "Nizam Package", "description": "Tidak cuma catat. analisis dan keluarkan rekomendasi keputusan bisnis"}, {"title": "Bonus implementasi", "description": "Checklist eksekusi, template SOP, dan arahan follow-up tim sales."}, {"title": "Pendampingan awal", "description": "Sesi singkat untuk membantu tim memahami skenario penggunaan paling relevan."}], "price_label": "Mulai dari penawaran spesial hari ini", "subheadline": "Tidak cuma catat. analisis dan keluarkan rekomendasi keputusan bisnis", "proof_points": [{"label": "Positioning", "value": "Pesan utama langsung jelas"}, {"label": "CTA", "value": "Arahkan visitor ke aksi inti"}, {"label": "Tracking", "value": "Siap Meta Pixel & lead capture"}], "published_at": "2026-03-29T22:57:40.828+00:00", "testimonials": [{"name": "Calon Case Study #1", "role": "Owner / Founder", "quote": "Setelah memakai pendekatan ini, penyampaian value Nizam Package jadi jauh lebih jelas dan closing terasa lebih cepat."}, {"name": "Calon Case Study #2", "role": "Head of Sales", "quote": "Tim kami akhirnya punya halaman penawaran yang rapi, tidak berputar-putar, dan enak dikirim ke prospek."}], "urgency_text": "Slot onboarding promo terbatas untuk batch bulan ini.", "form_settings": {"title": "Mau lihat bagaimana Nizam Package cocok untuk bisnis Anda?", "enabled": true, "ctaLabel": "Saya Mau Penawarannya", "subtitle": "Isi data singkat Anda. Tim kami akan follow-up cepat dengan detail promo, bonus, dan demo.", "successMessage": "Lead Anda sudah masuk. Tim kami akan segera menghubungi Anda."}, "meta_pixel_id": "", "guarantee_text": "Konsultasi kebutuhan dan mapping solusi sebelum deal.", "hero_image_alt": "Nizam Package visual", "hero_image_url": "", "primary_cta_url": "#lead-form", "target_a