	('e4e88599-72ee-498c-adaf-a6a2dc1d8408', 'f3b6d288-d89c-4945-8664-68bb7b08ac05', 'Wedding', 'wedding', 'DRAFT', 'Lead Capture Campaign 2026', 'Catering Wedding Package untuk Calon PEngantin', 'wujudkan pernikahan impian anda', 'Catering Wedding Package membantu Calon PEngantin bergerak lebih cepat dengan penawaran yang jelas, positioning yang tegas, dan ajakan aksi yang tidak membingungkan calon buyer.', 'Calon PEngantin', 'Mulai dari penawaran spesial hari ini', 'Bonus onboarding, template follow-up, dan panduan implementasi.', 'Konsultasi kebutuhan dan mapping solusi sebelum deal.', 'Slot onboarding promo terbatas untuk batch bulan ini.', '', 'Catering Wedding Package visual', 'Jadwalkan Demo', '#lead-form', 'Lihat Benefit', '#benefits', 'Catering Wedding Package | Solusi untuk Calon PEngantin', 'Catering Wedding Package membantu Calon PEngantin mendapatkan hasil lebih cepat dengan proses yang lebih rapi, penawaran yang lebih kuat, dan CTA yang lebih jelas.', '', '{"text": "#1E3A8A", "muted": "#1D4ED8", "accent": "#1D4ED8", "border": "#93C5FD", "surface": "#EFF6FF", "accentSoft": "#DBEAFE", "surfaceAlt": "#F8FAFC", "accentContrast": "#EFF6FF"}', '[{"label": "Positioning", "value": "Pesan utama langsung jelas"}, {"label": "CTA", "value": "Arahkan visitor ke aksi inti"}, {"label": "Tracking", "value": "Siap Meta Pixel & lead capture"}]', '[{"title": "Pesan penjualan lebih tajam", "description": "Konten halaman langsung menekankan nilai Catering Wedding Package untuk Calon PEngantin."}, {"title": "Meyakinkan sejak layar pertama", "description": "Hero section, social proof, offer stack, dan FAQ ditata agar visitor cepat paham dan percaya."}, {"title": "Siap dipakai untuk iklan", "description": "Tracking Meta Pixel dan formulir lead sudah disiapkan agar campaign bisa langsung jalan."}]', '[{"title": "Catering Wedding Package", "description": "wujudkan pernikahan impian anda"}, {"title": "Bonus implementasi", "description": "Checklist eksekusi, template SOP, dan arahan